"use strict";(self["webpackChunkiacss"]=self["webpackChunkiacss"]||[]).push([[180],{180:function(a,e,i){i.r(e),i.d(e,{default:function(){return h}});i(7658);var t=i(3396);const s=a=>((0,t.dD)("data-v-6021aa20"),a=a(),(0,t.Cn)(),a),n={class:"view-container"},o=s((()=>(0,t._)("div",{class:"view-title"},"Conference News",-1))),r={class:"view-main"},l={class:"view-section"},c=(0,t.uE)('<div class="view-section-title small" data-v-6021aa20>First Call for Papers</div><p data-v-6021aa20>Dear Colleagues and Friends,</p><p data-v-6021aa20>It is with great pleasure that we can announce that <strong data-v-6021aa20>the 15th International Symposium on Computer Science in Sport (IACSS 2025)</strong> will be held at the Tokyo Gakugei University, Japan, from the 13-15th of September 2025 .</p><p data-v-6021aa20>The program will feature presentations from distinguished keynote speakers and leading experts, along with oral and poster presentations from top researchers addressing cutting-edge topics and the latest technologies in the field of Computer Science in Sport.</p><p data-v-6021aa20>We invite interested scientists, experts, students and professionals in this field to submit contributions on current advancements in various areas of computer science related to sport.</p><p data-v-6021aa20>Further details will be available on the <a href="https://iacssconference.org/" data-v-6021aa20>conference website</a>.</p><div class="news-subsection" data-v-6021aa20><div class="view-section-title small" data-v-6021aa20>Conference themes</div><p data-v-6021aa20><i data-v-6021aa20>Computer Science in Sport</i>: Modeling and Simulation, Data Analysis, Image Processing, Multimedia, Virtual Reality, Visualization and Visual Analysis, Human Computer Interaction, Computer Vision, Big Bata, Internet of Things, Robotics, Information Systems, Machine Learning and Data Mining.</p><p data-v-6021aa20><i data-v-6021aa20>Examples for Special Applications</i>: Feedback Systems, Predictive Modeling, Decision Support, Digital Games, Network Analysis, Complex Systems Analysis, Sequence Analysis, Sensor Fusion.</p><p data-v-6021aa20><i data-v-6021aa20>Other related topics</i>: sports education, athletic training, sports biomechanics, exercise physiology, sports medicine, sports psychology, and sports engineering.</p></div><div class="news-subsection" data-v-6021aa20><div class="view-section-title small" data-v-6021aa20>Date and deadlines</div><ul class="withicon" data-v-6021aa20><li data-v-6021aa20>Abstract submission opens: 30.11.2024</li><li data-v-6021aa20>Second call for papers: 05.01.2025</li><li data-v-6021aa20>Third call for papers: 15.03.2025</li><li data-v-6021aa20>Abstract submission deadline: 15.04.2025 at 23:59 AoE (UTC - 12)</li><li data-v-6021aa20>Author notification (abstract): 15.05.2025</li></ul></div><div class="news-subsection" data-v-6021aa20><div class="view-section-title small" data-v-6021aa20>Publications:</div><p data-v-6021aa20>Authors whose papers meet the publication requirements of the association’s journal, <i data-v-6021aa20>International Journal of Computer Science in Sport</i> (IJCSS), will be invited to submit a full paper. The submission will undergo the regular submission process, peer review, and open-access publication by IJCSS. For details, please visit: <a href="https://sciendo.com/journal/IJCSS" target="_blank" data-v-6021aa20>https://sciendo.com/journal/IJCSS</a> (For Authors - Article Publishing Charges). </p><p data-v-6021aa20>Authors of other papers may also be invited to submit full papers (8-15 pages), which will be published by <strong data-v-6021aa20>Springer</strong> as part of the conference proceedings series <i data-v-6021aa20>Lecture Notes on Data Engineering and Communications Technologies</i>.</p></div><div class="news-subsection" data-v-6021aa20><div class="view-section-title small" data-v-6021aa20>Contact us:</div><p data-v-6021aa20>Naoki Suzuki, Ph.D.</p><p data-v-6021aa20>Associate Professor, Tokyo Gakugei University</p><p data-v-6021aa20>Email: iacss.2025.tgu@gmail.com</p></div>',10);function d(a,e,i,s,d,p){return(0,t.wg)(),(0,t.iD)("div",null,[(0,t._)("div",n,[o,(0,t._)("div",r,[(0,t._)("div",l,[c,(0,t._)("p",null,[(0,t.Uk)("Please click "),(0,t._)("span",{class:"link_text",onClick:e[0]||(e[0]=e=>a.$router.push("/2025/submission"))},"here"),(0,t.Uk)(" to find the abstract template for IACSS 2025.")])])])])])}var p={name:"ConferenceNewsView"},v=i(89);const u=(0,v.Z)(p,[["render",d],["__scopeId","data-v-6021aa20"]]);var h=u}}]);
